@module arrangePage  src=arrangePage.lua  loc=723  sha=588f8f3  mode=chunk
@deps cm, cmgr, chrome, gui, onDive, onTakeProperties, modalHost

# Invariants & contracts
  @invariant  render + input only — no am reference; all project queries and mutations go through av.
  @invariant  arrange page is project-wide — bind() takes no take and never re-keys cm.
  @invariant  key bindings here; command bodies in av; coord pushes the scope on activation.

# Shapes
  @shape  body = grid pane (variable width) | PALETTE_W palette; palette shows slots for the track under av:cursorCol().
  @shape  press = { qn, row, col, take, mode = 'move'|'resizeEnd', duplicate, moved, gutter, create } — nil when no button down. Track-col: take/row/col/mode; gutter: qn+gutter=true; dbl-click: qn/col+create=true. moved flips at drag threshold.

# Imports
  @require util = 'util'  @ 9
  @require ImGui = 'imgui'  @ 15
  @require painter = 'painter'  @ 16

# Constructed sub-instances
  @construct av = util.instantiate('arrangeView')  @ 27

# Private state
  @state ctx = gui and gui.ctx or nil  @ 21
  @state monoFont = gui and gui.font or nil  @ 24
  @state uiSize = gui and gui.fontSize and gui.fontSize.ui or 12  @ 25
  @state ap = {}  @ 30
  @state PALETTE_W = 200  @ 32
  @state PANE_GAP = 11  @ 35
  @state QN_W, TRACK_W = 32, 72  @ 36
  @state GUTTER_PAD = 14  @ 39
  @state LOOP_PAD = 7  @ 42
  @state SLOT_KEY_W, SLOT_KIND_W = 18, 16  @ 44
  @state openCreateModal  @ 47
  @state press = nil  @ 53
      @invariant  drag relocates via am:startIsClear; cursor moves only on clean (no-drag) release.
      @invariant  gutter press drives REAPER transport — release sets edit cursor, drag sets loop range.
      @invariant  double-click on empty space starts a create press; release opens create modal.
  @state WHEEL_ROWS = 1  @ 54   -- cursor rows moved per mouse-wheel notch
  @state wheelAccum = 0  @ 55   -- fractional wheel carried between frames
  @state SLOT_FILL_ALPHA = 0.85  @ 77
  @state SLOT_BORDER_ALPHA = 0.75  @ 78
  @state colourCache = {}  @ 79
  @state HEADER_PAD = 8  @ 103
  @state HEADER_GAP = 4  @ 104
  @state CREATE_DEFAULT_BEATS = 8  @ 481
  @state arrange = cmgr:scope('arrange')  @ 672
      @invariant  createSlot (Ctrl+Enter) opens the create modal — the only slot-minting gesture.
  @state binds = {  @ 682

# Private functions
  -- Style + draw helpers
  @fn pushBodyStyles()  @ 59
  @fn popBodyStyles()  @ 67
  @fn rowLabel(row)  @ 71
      -- Row label = QN at the row's top edge. beatPerRow is integer-valued
      -- in normal use (1, 4, 8, 16); show the QN as an integer.
  @fn slotColours(colourIdx, focused)  @ 80
  -- Grid pane
  @fn floorTo(v, step)  @ 107
      -- Snap a click's QN down to the top edge of the row box it sits in.
  @fn gridGeom(nTracks)  @ 111
      -- Shared (col,row)→screen transform for mouse pass and paint pass: both call gridGeom at the
      -- same layout-cursor position, so hit-test and draw resolve through one mapping.
  @fn handleGridMouse(nTracks)  @ 136
      -- Runs before renderGrid so in-flight drag/loop/create candidates are ready for the paint pass.
      -- Must run inside ##arrangeGrid so IsWindowHovered resolves correctly.
  @fn renderGrid(tracks, nTracks, dragCand, loopCand, createCand)  @ 226
  -- Palette pane
  @fn focusedSlotEntry(slots, slotIdx)  @ 433
      -- Locate slot in trackSlots() output (packed array, not indexed by slotIdx).
      -- Returns nil when no slot is focused or the focused slot index isn't populated.
  @fn renderPaletteHeader(focusedTrack)  @ 443
      -- Hand-drawn so the header height and divider position match the grid's by construction —
      -- both panes share the renderBody `oy`, so the divider aligns across PANE_GAP without measurement.
  @fn openRenameModal(trackIdx, slotIdx, currentName)  @ 460
  @fn openDeleteModal(trackIdx, slot)  @ 469
  @fn renderPaletteActions(focusedTrack, focusedSlot)  @ 517
  @fn renderPaletteList(slots)  @ 536
      -- Three columns: key (monospace — hotkey), kind glyph, name (UI font).
      -- Selectable in col 0 with SpanAllColumns; key text painted on top via SameLine.
  @fn renderPalette(tracks)  @ 569
  @fn placeKey(slotIdx)  @ 710
      -- Place-command keys: 0..9 → digit keys, 10..35 → letters, 36..61 →
      -- Shift+letter. ImGui.Key_0 + n and Key_A + n are contiguous.

# Public API (ap:*)
  @api ap:bind()  @ 588
      @contract  bind takes no take — arrange is project-wide; coord may call with nil or a take.
  @api ap:unbind()  @ 589
  @api ap:revealTake(reaperTake)  @ 592
      @contract  positions cursor on the take wrapping `reaperTake` and focuses it; no-op if not on grid.
  @api ap:seedCursorFromReaper()  @ 595
      @contract  seeds cursor/focus from am:initialCursor (first selected take, else edit cursor).
  @api ap:renderToolbarBits(_)  @ 597
  @api ap:renderBody(_, w, h, dispatch)  @ 602
      @invariant  grid is hand-drawn (no ImGui table) — tints, gridlines, take rects, cursor on top.
      @contract  pushes parchment body palette (coord popped chrome before); palette tables need it.
      @contract  invokes dispatch at end-of-body so arrange-scope keys reach the dispatcher.
  @api ap:renderStatusBar(_)  @ 649
  @api ap:focusState()  @ 658
      @contract  acceptCmds=false if picker active, any item active, or modal was open at frame start.

